				{% block content %}
				{% block object-tools %}{% endblock %}
				{{ content }}
				{% endblock %}
				{% block sidebar %}{% endblock %}
				<br class="clear" />
			</div>
			<!-- END Content -->

			{% block footer %}<div id="footer"></div>{% endblock %}
		</div>
		<!-- END Container -->

	</div>
	<!-- END Wrapper -->

</body>

